//迭代加深IDA*
#include <bits/stdc++.h>
using namespace std;

const int N=15;

int t,n,q[N],w[5][N];

int f(){//估值函数
    int tot=0;
    for(int i=0;i+1<n;i++)
        if(q[i+1]!=q[i]+1)
            tot++;
    return (tot+2)/3;
}

bool dfs(int dep,int md){
    if(dep+f()>md)
        return 0;
    if(f()==0)
        return 1;
    for(int len=1;len<=n;len++)
        for(int l=0;l+len-1<n;l++){
            int r=l+len-1;
            for(int k=r+1;k<n;k++){
                memcpy(w[dep],q,sizeof(q));
                int y=l;
                for(int x=r+1;x<=k;x++,y++)
                    q[y]=w[dep][x];
                for(int x=l;x<=r;x++,y++)
                    q[y]=w[dep][x];
                if(dfs(dep+1,md))
                    return 1;
                memcpy(q,w[dep],sizeof(q));
            }
        }
    return 0;
}

int main(){
    scanf("%d",&t);
    while(t--){
        scanf("%d",&n);
        for(int i=0;i<n;i++)
            scanf("%d",&q[i]);
        int dep=0;
        while(dep<5 && !dfs(0,dep))
            dep++;
        if(dep==5)
            puts("5 or more");
        else
            printf("%d\n",dep);
    }
    return 0;
}
